import "./styles.css";
import { BrowserRouter, Routes, Route, NavLink } from "react-router-dom";


import Buttons from "./Buttons";
import IssueCardDemo from "./Issue-Card";
import CompareCardDemo from "./Compare-Card";


function Navigation() {
  return(
  <div class="p-4 mb-4 flex items-center gap-4">
    <a class="" href="/">Home</a>
    <a class="" href="/buttons">Buttons</a>
    <a class="" href="/issues">Issues</a>
    <a class="" href="/compare">Compare</a>

        <NavLink exact activeClassName='is-active' to='/'>Home</NavLink>
        <NavLink activeClassName='is-active' to='/about'>About</NavLink>
\
  </div>
)}

export default function App() {
  return (
    <div>
      <Navigation /> 
      <Routes>
        <Route index element={<div>Home</div>} />
        <Route path="home" element={<div>Home</div>} />
        {/* <Route path="user" element={<User />}>
          <Route path="profile" element={<Profile />} />
          <Route path="account" element={<Account />} />
        </Route> */}
        <Route path="buttons" element={<Buttons />} />
        <Route path="issues" element={<IssueCardDemo />} />
        <Route path="compare" element={<CompareCardDemo />} />
      </Routes>

    </div>
  );
}
